sp_widget.client_script:
function($scope) {
	/* widget controller */
	var c = this;

	$scope.formatDate = function(){
		var date = moment().month($scope.data.monthServer).year($scope.data.yearServer).format("MMMM/YYYY");
		return date;
	};

	setTimeout(function() {

		$scope.severityWarning = c.data.severityWarning;
		$scope.severityInfomation = c.data.severityInfomation;
		$scope.severityHigh = c.data.severityHigh;
		$scope.severityDisaster = c.data.severityDisaster;
		$scope.securityAverage = c.data.securityAverage;

		var activeData = {
			datasets: [{
				data: [$scope.severityInfomation, $scope.severityWarning, $scope.securityAverage , $scope.severityHigh, $scope.severityDisaster],
				backgroundColor: ['#A8C639', '#FEE700', '#8fdaff', '#F69F2A', '#D80000'],
				borderWidth: 0,
				hoverBorderWidth: 0,
				hoverBackgroundColor:	['#A8C639', '#FEE700', '#8fdaff', '#F69F2A', '#D80000']
			}],
			labels: [
				'Information',
				'Warning',
				'Average',
				'High Priority',
				'Disaster',
			]
		};

		var activeOptions = {
			responsive: false,
			cutoutPercentage	: 60,
			legend: {
				display: false
			}
		};

		var activeChart = document.getElementById('activeChart').getContext('2d');

		$scope.down = c.data.down;
		$scope.up = c.data.up;

		var myActiveChart = new Chart(activeChart, {
			type: 'doughnut',
			data: activeData,
			options: activeOptions
		}); 

		var equipmentsData = {
			datasets: [{
				data: [$scope.up, $scope.down],
				backgroundColor: ['#A8C639', '#D80909'],
				borderWidth: 0,
				hoverBorderWidth: 0,
				hoverBackgroundColor:	['#A8C639', '#D80909']
			}],
			labels: [
				'Up and Running',
				'Down'
			]
		};

		var equipmentsOptions = {
			responsive: false,
			cutoutPercentage	: 60,
			legend: {
				display: false
			}
		};

		$scope.monitored = c.data.monitored;
		$scope.unmonitored = c.data.unmonitored;

		var equipmentsChart = document.getElementById('equipmentsChart').getContext('2d');

		var myEquipmentsChart = new Chart(equipmentsChart, {
			type: 'doughnut',
			data: equipmentsData,
			options: equipmentsOptions
		}); 

		var coverageData = {
			datasets: [{
				data: [$scope.monitored, $scope.unmonitored],
				backgroundColor: ['#A8C639', '#D80909'],
				borderWidth: 0,
				hoverBorderWidth: 0,
				hoverBackgroundColor:	['#A8C639', '#D80909']
			}],
			labels: [
				'Equipments monitored',
				'Equipments not monitored'
			]
		};

		var coverageOptions = {
			responsive: false,
			cutoutPercentage	: 60,
			legend: {
				display: false
			}
		};

		var coverageChart = document.getElementById('coverageChart').getContext('2d');

		var myCoverageChart = new Chart(coverageChart, {
			type: 'doughnut',
			data: coverageData,
			options: coverageOptions
		}); 

	}, 2000);
}

sp_widget.css:
.fullscreen-button {
  width: 20px;
  height: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #A8A8A8;
  color: #fff;

  .fa {
    font-size: 1.6rem;
  }
}

.charts-grid {
  margin-top: 30px;

  > .row > .col-md-6:first-of-type {
    padding-right: 0;
  }

  > .row > .col-md-6:last-of-type {
    padding-left: 0;

    .chart-box {
      border-left: 0;
    }
  }

  > .row:last-of-type > .col-md-6 {
    margin-top: -1px;
  }
}

.chart-title {
  font-size: 1.2em;
  font-family: var(--eq-font-family);
  font-weight: var(--eq-font-weight-light);
}

.donut-chart {
  //margin-top: 8px;
  //margin-bottom: 24px;
  //position: relative;
  margin-left: 200px;
  max-height: 200px;
  max-width: 400px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-wrap: wrap;

  span {
    //margin: auto;
    //display: table;
    position: absolute;
    //top: 0;
    //bottom: 0;
    left: auto;
    //-webkit-transform: translateX(-50%);
    //transform: translateX(-50%);
    font-size: 1.8em;
    font-family: var(--eq-font-family);
    font-weight: var(--eq-font-weight-light);

    small {
      margin-top: -3px;
      margin-bottom: 3px;
      display: block;
      font-size: 12px;
    }
  }

  canvas {
    //margin-left: 40%;
    //width: 80% !important;
    height: auto !important;
    //position: absolute;
    //margin-top: 50px;
  }
  
  &.no-chart {
  	display: block;
  }
}

.chart-box {
  padding: 16px;
  height: 300px;
  border: 1px solid #D9D9D9;

  .text-muted {
    font-family: var(--eq-font-family);
    font-weight: var(--eq-font-weight-light);
    font-size: 1em;
  }

  .text-large {
    margin-top: 48px;
    left: 50%;
    font-family: var(--eq-font-family);
    font-weight: var(--eq-font-weight-semibold);
    font-size: 4em;
  }
}

.chart-legend {
  max-width: 50%;
  position: absolute;
  top: 12px;
  text-align: initial;

  > li {
    margin-bottom: 16px;
    padding-left: 36px;
    width: 100%;
    font-size: 1.1em;
    font-family: var(--eq-font-family);
    font-weight: var(--eq-font-weight-light);
    white-space: initial;

    > span {
      width: 20px;
      height: 20px;
      top: 3px;
      border-radius: 0;
    }
  }
}

.legend-red {
  background: #D80000;
}

.legend-orange {
  background: #FF9002;
}

.legend-yellow {
  background: #FEE700;
}

.legend-info {
  background: #A8C639;
}

.legend-green {
  background: #A8C639;
}
.legend-average {
  background-color: #8fdaff;
}

.maximize {
  .chart-box {
    height: 400px;
  }
  
  .donut-chart {
  	margin-left: 250px;
  }
}

.pruned-msg {
  padding-bottom: 10px;
  padding-left: 4px;
  text-align: center;
}
.pruned-msg-filter-pad {
  padding-top:8px;
}

sp_widget.script:
(function() {

   // Get user account
	var customerPermission = new EQIX_Customer_Permissions();
	var account_id = customerPermission.getActiveAccountSysId();
    var userPermission = customerPermission.checkTablePermission('u_event_management');

	data.amounts = [];
	data.dates = [];

	//// at ACL level no restriction at table level, contacts have access to read their changes created by default, even if no records in the query should receive message "no records to display"
	data.canRead = true;

	var grAccount = new GlideRecord('customer_account');
	if (!grAccount.get(account_id)) {
		return;
	}

	//get amount of data event for an specific event.
	var grEvent = new GlideAggregate('u_event_management');	         
	grEvent.addEncodedQuery('u_equipment.u_monitored=true^u_state=0^u_trigger_value=1^u_normalization_eventISEMPTY^u_trigger_severityIN1,2,3,4,5^u_account='+account_id);
	grEvent.addAggregate('COUNT','u_trigger_severity');
	grEvent.query();

	while(grEvent.next()){
		var amountEvent = grEvent.getAggregate('COUNT', 'u_trigger_severity');
		var severity = grEvent.getValue('u_trigger_severity');

		var objEvent = {
			quant: amountEvent,
			severity: severity
		};
		data.amounts.push(objEvent);

		if(objEvent.severity == 2){
			data.severityWarning = objEvent.quant;
		}else if(objEvent.severity == 1){
			data.severityInfomation = objEvent.quant;
		}else if(objEvent.severity == 3){
			data.securityAverage = objEvent.quant;
		}else if(objEvent.severity == 4){
			data.severityHigh = objEvent.quant;
		}else{
			data.severityDisaster = objEvent.quant;
		}
	}

	var grEventTotal = new GlideAggregate('u_event_management');	         
	grEventTotal.addEncodedQuery('u_equipment.u_monitored=true^u_state=0^u_trigger_value=1^u_normalization_eventISEMPTY^u_normalization_eventISEMPTY^u_trigger_severityIN1,2,3,4,5^u_account='+account_id);
	grEventTotal.addAggregate('COUNT');
	grEventTotal.query();

	while(grEventTotal.next()){
		var total = grEventTotal.getAggregate('COUNT');
		data.total = total;
	}

	var grTotalAlarms = new GlideAggregate('u_event_management');	         
	grTotalAlarms.addEncodedQuery('u_trigger_value=1^sys_created_onONThis month@javascript:gs.beginningOfThisMonth()@javascript:gs.endOfThisMonth()^u_account='+account_id);
	grTotalAlarms.addAggregate('COUNT');
	grTotalAlarms.query();

	while(grTotalAlarms.next()){
		var totalAlarms = grTotalAlarms.getAggregate('COUNT');
		data.totalAlarms = totalAlarms;
	}

	var nowDateTime=gs.nowDateTime();
	var gdt = new GlideDateTime(nowDateTime);
	var month=gdt.getMonth();
	var year=gdt.getYear();

	data.monthServer = month - 1;
	data.yearServer = year;

	var ciList = 'sys_class_name=cmdb_ci_server^ORsys_class_name=cmdb_ci_ip_switch^ORsys_class_name=u_cmdb_ci_private_connectivity_lmc^ORsys_class_name=cmdb_ci_firewall_network^ORsys_class_name=cmdb_ci_vm_instance^ORsys_class_name=u_cmdb_ci_virtual_private_servers^ORsys_class_name=cmdb_ci_san^ORsys_class_name=cmdb_ci_vmware_instance^ORsys_class_name=cmdb_ci_ip_router^ORsys_class_name=cmdb_ci_cmp_resource^ORsys_class_name=cmdb_ci_computer^ORsys_class_name=cmdb_ci_dns_name^ORsys_class_name=cmdb_ci_esx_server^ORsys_class_name=cmdb_ci_firewall_cluster_fortinet^ORsys_class_name=cmdb_ci_firewall_device_fortinet^ORsys_class_name=cmdb_ci_hyper_v_instance^ORsys_class_name=cmdb_ci_ids_network^ORsys_class_name=cmdb_ci_ip_firewall^ORsys_class_name=cmdb_ci_lb_a10^ORsys_class_name=cmdb_ci_linux_server^ORsys_class_name=cmdb_ci_msd^ORsys_class_name=cmdb_ci_net_app_server^ORsys_class_name=cmdb_ci_net_traffic^ORsys_class_name=cmdb_ci_outofband_device^ORsys_class_name=cmdb_ci_storage_server^ORsys_class_name=cmdb_ci_storage_switch^ORsys_class_name=cmdb_ci_vcenter^ORsys_class_name=cmdb_ci_vcenter_cluster^ORsys_class_name=cmdb_ci_web_site^ORsys_class_name=cmdb_ci_win_cluster^ORsys_class_name=cmdb_ci_win_cluster_resource^ORsys_class_name=cmdb_ci_win_server^ORsys_class_name=u_cmdb_ci_cloud_management_compute^ORsys_class_name=u_cmdb_ci_cloud_management_container^ORsys_class_name=u_cmdb_ci_cloud_management_database^ORsys_class_name=u_cmdb_ci_cloud_management_gateway_firewall^ORsys_class_name=u_cmdb_ci_cloud_management_object^ORsys_class_name=u_cmdb_ci_cloud_management_storage^ORsys_class_name=u_cmdb_ci_customer_vm_instance^ORsys_class_name=u_cmdb_ci_data_hardware_storage^ORsys_class_name=u_cmdb_ci_nhlb^ORsys_class_name=u_cmdb_ci_tape_library^ORsys_class_name=u_cmdb_ci_vip_cluster^ORsys_class_name=u_cmdb_ci_virtual_network_edge_device^ORsys_class_name=u_customer_provider_equipment^ORsys_class_name=u_private_connectivity_branch_locations';
	var count = new GlideAggregate('cmdb_ci');
count.addEncodedQuery('u_account='+account_id+'^u_active_flag=true^' + ciList + '^NQu_account='+account_id+'^u_active_flag=true^sys_class_name=u_cmdb_ci_custom_product^u_custom_typeINAnti-DDoS,Dedicated Backup,Hardware - Load Balancer,Hardware - Blade Chassis,Hardware - Firewall,Hardware - Router,Hardware - Server,Hardware - Storage,Hardware - Switch,Hardware - Tape Library,Private Cloud');	
	count.addAggregate('COUNT','u_monitored');
	count.query();

	var countMonitored = 0;
	var countNotMonitored = 0;
	var down = 0;
	var up = 0;

    var grEventDown = new GlideAggregate('u_event_management');	
	var query = 'u_equipment.u_monitored=true^u_trigger_value=1^u_normalization_eventISEMPTY^u_account='+account_id+'^u_key_origSTARTSWITHicmpping';
	var ou = grAccount.getValue('u_operating_unit');
	if (ou == 'JP') {
		query = query + '^NQu_operating_unit=JP^u_trigger_value=1^u_normalization_eventISEMPTY^u_state=0^u_monitoring_parameter=PING^u_account=' + account_id;
	} else if (ou == 'ES') {
		query = query + '^NQu_operating_unit=ES^u_trigger_value=1^u_normalization_eventISEMPTY^u_state=0^u_monitoring_class=PPM_Device^u_account=' + account_id;
	}

	grEventDown.addEncodedQuery(query);
	grEventDown.addAggregate('COUNT','u_equipment');
	grEventDown.query();

	while(grEventDown.next()){
		down += 1;
	}

	data.monitored = 0;
    data.unmonitored = 0;
	while(count.next()){
		if (count.u_monitored == true){
			countMonitored = count.getAggregate('COUNT','u_monitored');
			data.monitored = countMonitored;
		}
		else{
			countNotMonitored = count.getAggregate('COUNT','u_monitored');
			data.unmonitored = countNotMonitored;
		}
	}

    var countUp = new GlideAggregate('cmdb_ci');
    countUp.addQuery('u_account', account_id);
    countUp.addQuery('u_monitored', true);
    countUp.query();
    if(countUp.next()){
        up = countUp.getRowCount();
    }

	data.down = down;
	data.up = up - down;
	var porcentage =  (parseInt(countMonitored) * 100) / (parseInt(countMonitored) + parseInt(countNotMonitored));
	data.porcentage = porcentage.toFixed(0) + "%";

})();
